def merge_break(blocks):
    left,right=blocks[107],blocks[108]
    assert left['text'].endswith('his brothers were') and right['text'].startswith('Sam and Grenn')
    left['text']+=' '+right['text']; left['end_page']=right['end_page']; del blocks[108]
    for i,b in enumerate(blocks,1): b['order']=i; b['id']=f"CH26-P{int(b['page']):03d}-{i:03d}"
    # Fix lost apostrophe-space in one extraction artifact.
    for b in blocks: b['text']=b['text'].replace("direwolf s shaggy", "direwolf’s shaggy")
    return blocks

